/**
 * Saída com nomes de colunas iguais à tabela Supabase (CSV).
 * Upsert em «CÓD INTERNO» (on_conflict na URL).
 */
const item = $input.first().json;
const body = item.body ?? item;
const expected = $env.WLADVAN_CATALOG_IMPORT_SECRET;
const hdrs = item.headers || {};
const secret =
  hdrs['x-wladvan-import-secret'] ||
  hdrs['X-Wladvan-Import-Secret'] ||
  body.import_secret;
if (!expected || String(secret) !== String(expected)) {
  throw new Error('Unauthorized: defina X-Wladvan-Import-Secret ou import_secret válido');
}
const products = body.products;
if (!Array.isArray(products) || products.length === 0) {
  throw new Error('Body deve conter products[] com ao menos um item');
}
function normSku(p) {
  const v = p.sku ?? p.cod_interno ?? p['CÓD INTERNO'] ?? p['COD INTERNO'];
  return v != null && String(v).trim() !== '' ? String(v).trim() : null;
}
function normName(p) {
  return String(p.name ?? p.produto ?? p.PRODUTO ?? '').trim();
}
const rows = products.map(function (p) {
  const rawPrice = p.price_brl ?? p.preco ?? p.PRECO;
  let price_brl = null;
  if (rawPrice !== undefined && rawPrice !== null && String(rawPrice).trim() !== '') {
    price_brl = Number(rawPrice);
  }
  const st = p.stock_total ?? p.estoque_total ?? p['ESTOQUE TOTAL'];
  let stock_total = null;
  if (st !== undefined && st !== null && String(st).trim() !== '') {
    stock_total = Number(String(st).replace(',', '.'));
  }
  const pst = p.product_status ?? p.status ?? p.STATUS;
  const active =
    p.active === false
      ? false
      : pst != null && String(pst).toUpperCase().indexOf('INAT') >= 0
        ? false
        : true;
  const mf =
    p.manufacturer_code != null && String(p.manufacturer_code).trim() !== ''
      ? String(p.manufacturer_code).trim()
      : p.cod_fabricante != null && String(p.cod_fabricante).trim() !== ''
        ? String(p.cod_fabricante).trim()
        : null;
  const row = {
    'CÓD INTERNO': normSku(p),
    'PRODUTO': normName(p),
    'CÓD FABRICANTE': mf,
    STATUS: pst != null ? String(pst).trim() : null,
    'ESTOQUE TOTAL': stock_total != null && !Number.isNaN(stock_total) ? stock_total : null,
    active,
  };
  if (price_brl != null) row.price_brl = price_brl;
  if (p.description != null) row.description = String(p.description);
  if (p.brand != null) row.brand = String(p.brand);
  if (p.vehicle_models != null) row.vehicle_models = String(p.vehicle_models);
  if (p.category != null) row.category = String(p.category);
  return row;
});
for (const r of rows) {
  if (!r['PRODUTO']) throw new Error('Cada item precisa de PRODUTO');
  if (r['CÓD INTERNO'] == null) throw new Error('Cada item precisa de CÓD INTERNO');
  if (r.price_brl != null && (Number.isNaN(r.price_brl) || r.price_brl < 0)) {
    throw new Error('price_brl inválido para ' + r['CÓD INTERNO']);
  }
}
return [{ json: { rows, count: rows.length } }];
